// ================================================================
// Deep Research Engine v1 — Multi-phase parallel research pipeline
// ================================================================
// Phase 1: PLAN — Generate diverse search queries from topic
// Phase 2: SEARCH — Parallel SearXNG queries
// Phase 3: FETCH — Parallel URL content extraction
// Phase 4: ANALYZE — Identify gaps, generate follow-ups
// Phase 5: SEARCH II — Follow-up queries in parallel
// Phase 6: FETCH II — Read new sources
// Phase 7: SYNTHESIZE — Produce structured research report
// ================================================================

const SEARXNG_URL = 'http://192.168.1.141:8888';
const OLLAMA_URL = 'http://192.168.1.110:11434';
const RESEARCH_MODEL = 'qwen3.5:27b';
const FAST_MODEL = 'qwen3.5:27b';

const input = $input.item.json.body || $input.item.json;
const topic = input.topic || input.query || '';
const depth = input.depth || 'standard'; // 'quick', 'standard', 'deep'
const focus = input.focus || ''; // optional focus area
const maxSources = depth === 'deep' ? 15 : depth === 'quick' ? 5 : 10;
const doFollowUp = depth !== 'quick';

const timeline = [];
const allSources = [];
let totalSearches = 0;
let totalFetches = 0;

function log(phase, msg) {
  timeline.push({ phase, message: msg, time: new Date().toISOString() });
}

// ── Helper: Call Ollama ──
async function askAI(prompt, model, maxTokens = 4096) {
  try {
    const resp = await fetch(`${OLLAMA_URL}/api/generate`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        model: model || RESEARCH_MODEL,
        prompt: prompt,
        stream: false,
        options: { temperature: 0.3, num_predict: maxTokens },
      }),
      signal: AbortSignal.timeout(180000),
    });
    const data = await resp.json();
    return (data.response || '').trim();
  } catch (err) {
    log('ai_error', `AI call failed: ${err.message}`);
    return '';
  }
}

// ── Helper: Search SearXNG ──
async function search(query, engines = 'google,duckduckgo,brave,wikipedia') {
  totalSearches++;
  try {
    const params = new URLSearchParams({
      q: query,
      format: 'json',
      categories: 'general,science,it,news',
      engines: engines,
      language: 'en',
    });
    const resp = await fetch(`${SEARXNG_URL}/search?${params}`, {
      signal: AbortSignal.timeout(15000),
    });
    const data = await resp.json();
    return (data.results || []).slice(0, 8).map(r => ({
      title: r.title || '',
      url: r.url || '',
      snippet: (r.content || '').substring(0, 500),
      engine: r.engine || '',
    }));
  } catch (err) {
    log('search_error', `Search failed for "${query}": ${err.message}`);
    return [];
  }
}

// ── Helper: Fetch URL content ──
async function fetchUrl(url) {
  totalFetches++;
  try {
    const resp = await fetch(url, {
      signal: AbortSignal.timeout(10000),
      headers: { 'User-Agent': 'HyprChat-Research/1.0' },
      redirect: 'follow',
    });
    let text = await resp.text();
    // Strip HTML tags, scripts, styles
    text = text.replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '');
    text = text.replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '');
    text = text.replace(/<[^>]+>/g, ' ');
    text = text.replace(/\s+/g, ' ').trim();
    return text.substring(0, 6000);
  } catch (err) {
    return '';
  }
}

// ── Helper: Run searches in parallel ──
async function parallelSearch(queries) {
  const results = await Promise.allSettled(
    queries.map(q => search(q))
  );
  const allResults = [];
  for (let i = 0; i < results.length; i++) {
    if (results[i].status === 'fulfilled') {
      for (const r of results[i].value) {
        r.query = queries[i];
        allResults.push(r);
      }
    }
  }
  return allResults;
}

// ── Helper: Fetch URLs in parallel (with concurrency limit) ──
async function parallelFetch(urls, limit = 5) {
  const results = {};
  for (let i = 0; i < urls.length; i += limit) {
    const batch = urls.slice(i, i + limit);
    const settled = await Promise.allSettled(
      batch.map(url => fetchUrl(url))
    );
    for (let j = 0; j < settled.length; j++) {
      if (settled[j].status === 'fulfilled' && settled[j].value) {
        results[batch[j]] = settled[j].value;
      }
    }
  }
  return results;
}

// ── Helper: Deduplicate results by URL ──
function dedup(results) {
  const seen = new Set();
  return results.filter(r => {
    if (seen.has(r.url)) return false;
    seen.add(r.url);
    return true;
  });
}

// ================================================================
// PHASE 1: PLAN — Generate search queries
// ================================================================
log('plan', `Starting research on: ${topic}`);

const planPrompt = `You are a research planner. Given a topic, generate diverse search queries to thoroughly research it.

Topic: ${topic}${focus ? `\nFocus area: ${focus}` : ''}
Depth: ${depth}

Generate ${depth === 'deep' ? '8-10' : depth === 'quick' ? '3-4' : '5-7'} search queries that:
- Cover different aspects and angles of the topic
- Include specific technical terms where relevant
- Mix broad overview queries with specific detail queries
- Include queries for recent developments/news
- Include queries for authoritative/primary sources

Respond with ONLY the queries, one per line. No numbering, no explanations.`;

const planResponse = await askAI(planPrompt, FAST_MODEL, 1024);
const queries = planResponse
  .split('\n')
  .map(q => q.replace(/^\d+[\.\)\-]\s*/, '').trim())
  .filter(q => q.length > 5 && q.length < 200)
  .slice(0, depth === 'deep' ? 10 : depth === 'quick' ? 4 : 7);

log('plan', `Generated ${queries.length} search queries`);

if (queries.length === 0) {
  // Fallback: use the topic directly
  queries.push(topic);
  queries.push(`${topic} explained`);
  queries.push(`${topic} latest developments`);
}

// ================================================================
// PHASE 2: SEARCH — Parallel SearXNG queries
// ================================================================
log('search', `Executing ${queries.length} parallel searches`);

const searchResults = await parallelSearch(queries);
const dedupedResults = dedup(searchResults);

log('search', `Found ${dedupedResults.length} unique results from ${totalSearches} searches`);

// ================================================================
// PHASE 3: FETCH — Read top URLs concurrently
// ================================================================
// Score and rank results
const scoredResults = dedupedResults.map(r => {
  let score = 0;
  // Prefer authoritative domains
  const domain = (r.url || '').toLowerCase();
  if (domain.includes('wikipedia.org')) score += 3;
  if (domain.includes('arxiv.org')) score += 4;
  if (domain.includes('.gov')) score += 3;
  if (domain.includes('.edu')) score += 3;
  if (domain.includes('github.com')) score += 2;
  if (domain.includes('stackoverflow.com')) score += 2;
  if (domain.includes('nature.com') || domain.includes('science.org')) score += 4;
  // Penalize junk
  if (domain.includes('pinterest') || domain.includes('facebook') || domain.includes('twitter') || domain.includes('tiktok')) score -= 5;
  if (domain.includes('quora.com')) score -= 1;
  // Prefer results with substantial snippets
  if ((r.snippet || '').length > 100) score += 1;
  // Prefer results whose title matches the topic
  if ((r.title || '').toLowerCase().includes(topic.toLowerCase().split(' ')[0])) score += 1;
  return { ...r, score };
}).sort((a, b) => b.score - a.score);

const urlsToFetch = scoredResults
  .slice(0, maxSources)
  .map(r => r.url)
  .filter(u => u && u.startsWith('http'));

log('fetch', `Fetching ${urlsToFetch.length} top sources in parallel`);

const fetchedContent = await parallelFetch(urlsToFetch);
const fetchedCount = Object.keys(fetchedContent).length;

log('fetch', `Successfully read ${fetchedCount} pages`);

// Build source context
for (const r of scoredResults.slice(0, maxSources)) {
  const content = fetchedContent[r.url];
  allSources.push({
    title: r.title,
    url: r.url,
    snippet: r.snippet,
    content: content ? content.substring(0, 3000) : null,
    query: r.query,
    score: r.score,
  });
}

// ================================================================
// PHASE 4: ANALYZE — Identify gaps (if not quick mode)
// ================================================================
let followUpResults = [];

if (doFollowUp && allSources.length > 0) {
  log('analyze', 'Analyzing for gaps and follow-up queries');

  const sourcesSummary = allSources
    .slice(0, 8)
    .map((s, i) => `${i + 1}. "${s.title}" — ${s.snippet?.substring(0, 200) || 'No snippet'}`)
    .join('\n');

  const gapPrompt = `You are a research analyst. Given a topic and initial search results, identify what's MISSING and generate follow-up queries.

Topic: ${topic}${focus ? `\nFocus: ${focus}` : ''}

Initial results found:
${sourcesSummary}

What important aspects are NOT covered? Generate 3-4 follow-up search queries to fill gaps.
Focus on: missing perspectives, contradicting viewpoints, recent data/statistics, primary sources, expert opinions.

Respond with ONLY the queries, one per line.`;

  const gapResponse = await askAI(gapPrompt, FAST_MODEL, 512);
  const followUpQueries = gapResponse
    .split('\n')
    .map(q => q.replace(/^\d+[\.\)\-]\s*/, '').trim())
    .filter(q => q.length > 5 && q.length < 200)
    .slice(0, 4);

  if (followUpQueries.length > 0) {
    log('search_2', `Executing ${followUpQueries.length} follow-up searches`);

    // ================================================================
    // PHASE 5: SEARCH II — Follow-up queries
    // ================================================================
    followUpResults = await parallelSearch(followUpQueries);
    const newResults = dedup([...followUpResults]).filter(
      r => !allSources.some(s => s.url === r.url)
    );

    log('search_2', `Found ${newResults.length} new results`);

    // ================================================================
    // PHASE 6: FETCH II — Read new sources
    // ================================================================
    if (newResults.length > 0) {
      const newUrls = newResults
        .slice(0, 5)
        .map(r => r.url)
        .filter(u => u && u.startsWith('http'));

      log('fetch_2', `Fetching ${newUrls.length} follow-up sources`);

      const newContent = await parallelFetch(newUrls);
      const newFetchedCount = Object.keys(newContent).length;

      log('fetch_2', `Read ${newFetchedCount} additional pages`);

      for (const r of newResults.slice(0, 5)) {
        const content = newContent[r.url];
        allSources.push({
          title: r.title,
          url: r.url,
          snippet: r.snippet,
          content: content ? content.substring(0, 3000) : null,
          query: r.query,
          score: 0,
          is_followup: true,
        });
      }
    }
  }
}

// ================================================================
// PHASE 7: SYNTHESIZE — Write the research report
// ================================================================
log('synthesize', 'Generating research report');

// Build the knowledge context from all sources
const knowledgeContext = allSources
  .filter(s => s.content || s.snippet)
  .slice(0, 15)
  .map((s, i) => {
    const body = s.content
      ? s.content.substring(0, 2000)
      : s.snippet || '';
    return `[Source ${i + 1}: "${s.title}" — ${s.url}]\n${body}`;
  })
  .join('\n\n---\n\n');

const synthesizePrompt = `You are an expert research analyst. Write a comprehensive, well-structured research report based on the sources provided.

TOPIC: ${topic}${focus ? `\nFOCUS: ${focus}` : ''}

SOURCES:
${knowledgeContext}

Write a thorough report that:
1. Opens with a clear executive summary (2-3 sentences)
2. Covers all major aspects found in the sources
3. Notes areas of consensus and disagreement
4. Includes specific data, statistics, and quotes where available
5. Identifies limitations — what we couldn't find or verify
6. Ends with key takeaways

Format with clear section headers using ##.
Cite sources inline as [Source N].
Be factual, specific, and avoid vague generalities.
Length: ${depth === 'deep' ? '800-1200' : depth === 'quick' ? '300-500' : '500-800'} words.`;

const report = await askAI(synthesizePrompt, RESEARCH_MODEL, depth === 'deep' ? 8192 : 4096);

log('synthesize', `Report generated: ${report.length} chars`);

// ================================================================
// BUILD RESPONSE
// ================================================================
const sourcesFormatted = allSources
  .filter(s => s.title && s.url)
  .slice(0, 20)
  .map((s, i) => ({
    index: i + 1,
    title: s.title,
    url: s.url,
    query: s.query,
    is_followup: s.is_followup || false,
  }));

const response = {
  success: report.length > 100,
  topic: topic,
  focus: focus || null,
  depth: depth,
  report: report,

  // Metadata
  sources: sourcesFormatted,
  source_count: sourcesFormatted.length,
  total_searches: totalSearches,
  total_fetches: totalFetches,
  queries_used: queries,
  follow_up_queries: followUpResults.length > 0 ? followUpResults.map(r => r.query).filter((v, i, a) => a.indexOf(v) === i) : [],

  // Timeline for debugging
  timeline: timeline,
  total_time_ms: Date.now() - new Date(timeline[0]?.time || Date.now()).getTime(),
};

return { json: response };
